scripts.script:
// Shared by the vanilla-js, React and Vue builds: the labels, the per-type
// series shape and the active-button sync. The mutable current* state lives in
// each format's own wiring below (one live chart per generated page).
var LABELS = ['Direct', 'Organic', 'Referral', 'Social', 'Email']

function buildSeriesFor(type, values) {
  if (type === 'funnel') {
    var sorted = values.slice().sort(function (a, b) { return b - a })
    return [{ name: 'Sessions', data: sorted }]
  }
  if (type === 'bar' || type === 'pyramid') {
    return [{ name: 'Sessions', data: values.slice() }]
  }
  return values.slice()
}

function setActive(type, horizontal) {
  document.querySelectorAll('.actions button[data-type]').forEach(function (btn) {
    var btnType = btn.getAttribute('data-type')
    var btnH = btn.getAttribute('data-horizontal')
    var active =
      btnType === type &&
      (type !== 'bar' || String(horizontal) === btnH)
    btn.classList.toggle('active', active)
  })
}

chart.options:
chart: {
  id: 'morphChart',
  type: 'bar',
  height: 380,
  toolbar: {
    show: false
  },
  animations: {
    enabled: true,
    speed: 800,
    chartTypeMorph: {
      enabled: true,
      speed: 700,
    },
  },
},
grid: {
  show: false
},
labels: ['Direct', 'Organic', 'Referral', 'Social', 'Email'],
legend: { show: false },
plotOptions: {
  bar: {
    borderRadius: 4,
    distributed: true,
    barHeight: '99%',
  },
  radialBar: {
    inverseOrder: true,
    hollow: {
      size: '5%'
    },
    track: {
      show: false
    }
  },
  funnel: {
    shape: 'trapezoid',
  },
},
yaxis: {
  show: false,
  axisBorder: {
    show: false,
  }
},
xaxis: {
  labels: {
      show: false
  },
  axisBorder: {
    show: false,
  },
  axisTicks: {
    show: false,
  }
},
dataLabels: { enabled: false },
fill: {
  opacity: 0.9
},
stroke: {  lineCap: 'butt', width: 1, colors: ['#fff'] },

vanilla-js-script:
// LABELS, buildSeriesFor and setActive live in the shared head script; the
// current* state and the DOM wiring stay per-format.
var currentType = 'bar'
var currentHorizontal = false
var currentValues = [44, 55, 41, 27, 33]

setActive(currentType, currentHorizontal)

document.querySelectorAll('.actions button[data-type]').forEach(function (btn) {
  btn.addEventListener('click', function () {
    var nextType = btn.getAttribute('data-type')
    var nextHorizontal = btn.getAttribute('data-horizontal') === 'true'
    if (nextType === currentType && nextHorizontal === currentHorizontal) return
    currentType = nextType
    currentHorizontal = nextHorizontal
    setActive(currentType, currentHorizontal)
    chart.updateOptions({
      chart: { type: currentType },
      plotOptions: {
        bar: {
          horizontal: currentHorizontal,
        },
      },
      series: buildSeriesFor(currentType, currentValues),
      labels: LABELS,
    })
  })
})

document.querySelector('#randomize').addEventListener('click', function () {
  currentValues = currentValues.map(function () {
    return Math.floor(Math.random() * 80) + 10
  })
  chart.updateSeries(buildSeriesFor(currentType, currentValues))
})

var speedInput = document.querySelector('#speed')
var speedValue = document.querySelector('#speed-value')
speedInput.addEventListener('input', function () {
  var v = parseInt(speedInput.value, 10)
  speedValue.textContent = v
  chart.updateOptions(
    { chart: { animations: { chartTypeMorph: { speed: v } } } },
    false,
    false,
  )
})

react-script:
React.useEffect(() => {
  // The react-apexcharts wrapper owns the render, so reach the live instance by
  // its chart.id, then wire the same controls the vanilla build does. (LABELS,
  // buildSeriesFor and setActive live in the shared head script.) updateOptions
  // drives the chart instance directly, so no React state changes and the
  //  is never re-rendered under it.
  let chart
  let currentType = 'bar'
  let currentHorizontal = false
  let currentValues = [44, 55, 41, 27, 33]

  const timer = window.setInterval(() => {
    chart = ApexCharts.getChartByID('morphChart')
    if (!chart) return
    window.clearInterval(timer)

    setActive(currentType, currentHorizontal)

    document.querySelectorAll('.actions button[data-type]').forEach((btn) => {
      btn.addEventListener('click', () => {
        const nextType = btn.getAttribute('data-type')
        const nextHorizontal = btn.getAttribute('data-horizontal') === 'true'
        if (nextType === currentType && nextHorizontal === currentHorizontal) return
        currentType = nextType
        currentHorizontal = nextHorizontal
        setActive(currentType, currentHorizontal)
        chart.updateOptions({
          chart: { type: currentType },
          plotOptions: { bar: { horizontal: currentHorizontal } },
          series: buildSeriesFor(currentType, currentValues),
          labels: LABELS,
        })
      })
    })

    document.querySelector('#randomize').addEventListener('click', () => {
      currentValues = currentValues.map(() => Math.floor(Math.random() * 80) + 10)
      chart.updateSeries(buildSeriesFor(currentType, currentValues))
    })

    const speedInput = document.querySelector('#speed')
    const speedValue = document.querySelector('#speed-value')
    speedInput.addEventListener('input', () => {
      const v = parseInt(speedInput.value, 10)
      speedValue.textContent = v
      chart.updateOptions(
        { chart: { animations: { chartTypeMorph: { speed: v } } } },
        false,
        false,
      )
    })
  }, 50)

  return () => window.clearInterval(timer)
}, [])

vue-script:
mounted: function () {
  // The vue-apexcharts wrapper owns the render, so reach the live instance by
  // its chart.id, then wire the same controls the vanilla build does. (LABELS,
  // buildSeriesFor and setActive live in the shared head script.) updateOptions
  // drives the chart instance directly, so no reactive data changes and the
  //  is never re-rendered under it.
  var me = this
  var currentType = 'bar'
  var currentHorizontal = false
  var currentValues = [44, 55, 41, 27, 33]

  me.morphTimer = window.setInterval(function () {
    var chart = ApexCharts.getChartByID('morphChart')
    if (!chart) return
    window.clearInterval(me.morphTimer)

    setActive(currentType, currentHorizontal)

    document.querySelectorAll('.actions button[data-type]').forEach(function (btn) {
      btn.addEventListener('click', function () {
        var nextType = btn.getAttribute('data-type')
        var nextHorizontal = btn.getAttribute('data-horizontal') === 'true'
        if (nextType === currentType && nextHorizontal === currentHorizontal) return
        currentType = nextType
        currentHorizontal = nextHorizontal
        setActive(currentType, currentHorizontal)
        chart.updateOptions({
          chart: { type: currentType },
          plotOptions: { bar: { horizontal: currentHorizontal } },
          series: buildSeriesFor(currentType, currentValues),
          labels: LABELS,
        })
      })
    })

    document.querySelector('#randomize').addEventListener('click', function () {
      currentValues = currentValues.map(function () {
        return Math.floor(Math.random() * 80) + 10
      })
      chart.updateSeries(buildSeriesFor(currentType, currentValues))
    })

    var speedInput = document.querySelector('#speed')
    var speedValue = document.querySelector('#speed-value')
    speedInput.addEventListener('input', function () {
      var v = parseInt(speedInput.value, 10)
      speedValue.textContent = v
      chart.updateOptions(
        { chart: { animations: { chartTypeMorph: { speed: v } } } },
        false,
        false,
      )
    })
  }, 50)
},
beforeDestroy: function () {
  window.clearInterval(this.morphTimer)
},
